"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[9247],{5025(e,i,n){n.r(i),n.d(i,{assets:()=>m,contentTitle:()=>c,default:()=>u,frontMatter:()=>l,metadata:()=>t,toc:()=>h});const t=JSON.parse('{"id":"multisensory-experience/multisensory-experience-practical-insights","title":"Practical insights","description":"Practical insights 9 min","source":"@site/docs/05-multisensory-experience/03-practical-insights.mdx","sourceDirName":"05-multisensory-experience","slug":"/multisensory-experience/practical-insights","permalink":"/ms/multisensory-experience/practical-insights","draft":false,"unlisted":false,"editUrl":null,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"title":"Practical insights","id":"multisensory-experience-practical-insights","slug":"practical-insights","sidebar_position":3,"custom_edit_url":null,"readingTimeMinutes":9},"sidebar":"reportSidebar","previous":{"title":"Creative opportunities: Boosting \'presence\'","permalink":"/ms/multisensory-experience/creative-opportunities-boosting-presence"},"next":{"title":"In focus: Vision","permalink":"/ms/in-focus-vision/"}}');var s=n(4848),a=n(8453),r=(n(1558),n(6593),n(6419),n(1948),n(6112),n(4174),n(5765)),o=n(6617);const l={title:"Practical insights",id:"multisensory-experience-practical-insights",slug:"practical-insights",sidebar_position:3,custom_edit_url:null,readingTimeMinutes:9},c=void 0,m={},h=[{value:'Practical insights <span class="reading-time"><span>9 min</span></span>',id:"practical-insights-9-min",level:2},{value:'Latency tolerances <span class="reading-time"><span>10 min</span></span>',id:"latency-tolerances-10-min",level:3},{value:'Tolerance of spatial mismatches <span class="reading-time"><span>5 min</span></span>',id:"tolerance-of-spatial-mismatches-5-min",level:3},{value:'Prior experience and the assumption of unity <span class="reading-time"><span>5 min</span></span>',id:"prior-experience-and-the-assumption-of-unity-5-min",level:3},{value:'Perceptual &#39;filling in&#39; <span class="reading-time"><span>3 min</span></span>',id:"perceptual-filling-in-3-min",level:3},{value:'Multisensory attention <span class="reading-time"><span>2 min</span></span>',id:"multisensory-attention-2-min",level:3},{value:'Holistic experiential integration <span class="reading-time"><span>1 min</span></span>',id:"holistic-experiential-integration-1-min",level:3}];function d(e){const i={a:"a",em:"em",h2:"h2",h3:"h3",img:"img",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)(i.h2,{id:"practical-insights-9-min",children:["Practical insights ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"9 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"9 min"})})]}),"\n",(0,s.jsx)("span",{id:"latency-tolerances"}),"\n",(0,s.jsxs)(i.h3,{id:"latency-tolerances-10-min",children:["Latency tolerances ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"10 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"10 min"})})]}),"\n",(0,s.jsxs)(i.p,{children:["It is popular to benchmark creative technical solutions in terms of Quality of Service",(0,s.jsx)(o.A,{refNum:"46",refText:"Reference 46"}),", which encompasses terms such as bandwidth, jitter, packet loss and latency. Audiences on the other hand are concerned with the Quality of Experience",(0,s.jsx)(o.A,{refNum:"46",refText:"Reference 46"}),", encompassing subjective terms such as smoothness, responsiveness, comfort and immersion."]}),"\n",(0,s.jsx)(i.p,{children:"These two do not always align. Solutions that technically fall short in terms of strict Quality of Service thresholds can sometimes still deliver a satisfying experience if they remain within perceptual tolerance windows. On the other hand, despite meeting Quality of Service thresholds, something might feel 'just off' about an experience without careful thought to multisensory elements. This distinction helps guide where creative effort and technical effort are best invested."}),"\n",(0,s.jsx)(i.p,{children:"It is often difficult to ensure that information being presented to different senses arrives at exactly the same time. Fortunately, in integrating sensory information our brains can tolerate small mismatches in timing. This means that absolute zero-latency is not always necessary for an engaging, comfortable experience. The graph below illustrates the lags that can be tolerated for different tasks and information type."}),"\n",(0,s.jsx)(r.A,{}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsxs)(i.li,{children:["\n",(0,s.jsxs)(i.p,{children:[(0,s.jsx)(i.strong,{children:"Motion-to-Photon Latency in Gaming"}),": When a player moves their character, a traditional view is that there should be a minimal delay before this movement is reflected on screen. This delay is known as motion-to-photon latency. Studies on first-person targeting and competitive FPS play show that reducing local latency improves performance; performance differences are already measurable in the tens-of-milliseconds range",(0,s.jsx)(o.A,{refNum:"56,57",refText:"References 56,57"}),"."]}),"\n"]}),"\n",(0,s.jsxs)(i.li,{children:["\n",(0,s.jsxs)(i.p,{children:[(0,s.jsx)(i.strong,{children:"Remote Collaborative Performances"}),": When actors or musicians collaborate from different locations on the map, delays in audio and visual transmission can disrupt the natural flow of interaction, which can influence the quality of their performance and expressive nuance",(0,s.jsx)(o.A,{refNum:"58",refText:"Reference 58"}),". In networked music performance, 20\u201330 ms is often cited as a target that feels close to in-person playing, although tolerable delay depends on repertoire, rhythm, and performer adaptation",(0,s.jsx)(o.A,{refNum:"48",refText:"Reference 48"}),". That being said, large orchestras, spread over a 40ft area (12.2m), would have delays of 35\u201336 ms milliseconds due to speed of sound, implying that there are work arounds to this issue",(0,s.jsx)(o.A,{refNum:"47",refText:"Reference 47"}),' Out of curiosity, it is worth noting a striking parallel: the band AC/DC often performed within a few feet of each other, with Malcolm Young (rhythm guitar), Cliff Williams (bass) and Phil Rudd (drums) positioned very close and maintaining their famously precise rhythmic tightness: "',(0,s.jsx)(i.em,{children:"They didn't just play in time, they felt the time \u2014 the groove \u2014 together"}),'."',(0,s.jsx)(o.A,{refNum:"59",refText:"Reference 59"})]}),"\n"]}),"\n",(0,s.jsxs)(i.li,{children:["\n",(0,s.jsxs)(i.p,{children:[(0,s.jsx)(i.strong,{children:"Live Music Streaming"}),": When streaming a live music performance into viewers' homes, it is important to consider how latency affects the experience. A small mismatch between audio and video can be tolerated, but the acceptable limits depend on which signal leads. For broadcast-style audiovisual sync, viewers begin to detect mismatch at roughly 45 ms when audio leads video and 125 ms when video leads audio; average acceptability limits are wider, at about 90 ms for audio lead and 185 ms for video lead."]}),"\n"]}),"\n",(0,s.jsxs)(i.li,{children:["\n",(0,s.jsxs)(i.p,{children:[(0,s.jsx)(i.strong,{children:"Speed of sound"}),": Sound travels through air at approximately 343 meters per second, meaning it takes about 2.9 milliseconds to travel 1 metre. If you sit 10 metres from a stage, you will hear the performer about 29 milliseconds later than someone in the front row. Temperature also has a significant effect: the speed of sound increases by around 0.5\u20130.6 m/s for each 1\xb0C rise in air temperature",(0,s.jsx)(o.A,{refNum:"60",refText:"Reference 60"}),", with smaller contributions from humidity and air pressure. High frequencies are more dampened than lower frequencies, leading to a loss of brightness over distance. Here's an interesting thought: if a performer's mouth subtends about 2\xa0cm in your visual field at 1\xa0m but only 0.2\xa0cm at 10\xa0m (simply due to physics), lip-sync errors may be less perceptually obvious at that distance \u2014 but timing differences in sound remain important. This is one reason large venues and festivals strategically distribute speakers (\"delay towers\") to keep sound aligned across the audience area. A known issue is that audience members located between two towers may hear slightly misaligned signals, creating a hollow or echo-like effect. Much of the craft of setting up public address systems involves tuning these time delays and shaping directivity patterns to minimise overlap and interference",(0,s.jsx)(o.A,{refNum:"55,61",refText:"References 55,61"}),"."]}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(i.p,{children:["Tolerances also vary substantially from person to person. For example, children typically have a higher tolerance for audiovisual delays than adults",(0,s.jsx)(o.A,{refNum:"62",refText:"Reference 62"}),", people with Attention\u2011Deficit/Hyperactivity Disorder (ADHD) tend to have a lower tolerance",(0,s.jsx)(o.A,{refNum:"63",refText:"Reference 63"})," (narrower windows; note some recent counter evidence exists",(0,s.jsx)(o.A,{refNum:"64",refText:"Reference 64"}),"), and individuals with developmental dyslexia",(0,s.jsx)(o.A,{refNum:"65",refText:"Reference 65"})," or with schizophrenia",(0,s.jsx)(o.A,{refNum:"66",refText:"Reference 66"})," generally display higher tolerances (broader windows) for the same lags. Because inclusive design should cater for all, including the most sensitive groups, latency 'budgets' ought to be set just below the smallest empirically reported window, even if larger windows appear acceptable for other audiences."]}),"\n",(0,s.jsx)("span",{id:"tolerance-of-spatial-mismatches"}),"\n",(0,s.jsxs)(i.h3,{id:"tolerance-of-spatial-mismatches-5-min",children:["Tolerance of spatial mismatches ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"5 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"5 min"})})]}),"\n",(0,s.jsxs)(i.p,{children:["When sensory signals appear in roughly the same location, our brains tend to merge them. Interestingly, this principle can hold even if there is a small but noticeable gap. For example, in a ventriloquist's performance the puppeteer's mouth is the true source of sound, yet onlookers often perceive the puppet itself as talking",(0,s.jsx)(o.A,{refNum:"67",refText:"Reference 67"}),". Even when there is a 30\xb0 separation",(0,s.jsx)(o.A,{refNum:"68",refText:"Reference 68"})," between the puppet and the ventriloquist's mouth, observers often fuse the two. A variety of factors influence the level of acceptable variation, as outlined in the next section."]}),"\n",(0,s.jsx)("span",{id:"prior-experience-and-the-assumption-of-unity"}),"\n",(0,s.jsxs)(i.h3,{id:"prior-experience-and-the-assumption-of-unity-5-min",children:["Prior experience and the assumption of unity ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"5 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"5 min"})})]}),"\n",(0,s.jsxs)(i.p,{children:["If we believe that two signals share the same origin, our brains can tolerate more pronounced mismatches in timing or location than usual. Early work",(0,s.jsx)(o.A,{refNum:"69",refText:"Reference 69"})," showed that simply expecting signals to come from one source can override some discrepancies in timing or location. This is known as the 'assumption of unity' and it is strongly influenced by prior experience \u2013 the brain learns from repeated multisensory encounters, building strong associations that guide whether future signals are integrated. For example, we have a lot of practice seeing people speak, making us more likely to bind mouth movements with vocal sounds, and it is this prior experience that underlies the ventriloquist effect (with 30\xb0 separation being acceptable",(0,s.jsx)(o.A,{refNum:"68",refText:"Reference 68"}),"). If instead we see a random blinking light and hear a beep, we require a more precise matching of timing and location",(0,s.jsx)(o.A,{refNum:"70",refText:"Reference 70"})," (typical 20-25\xb0) before we will perceive them as originating from the same event, reflecting our limited experience of pairing such stimuli. This means that less precise matching can often be used for more commonly experienced multisensory events."]}),"\n",(0,s.jsx)(i.p,{children:(0,s.jsx)(i.img,{alt:"Figure 9: The &#39;Face on Mars&#39; captured by NASA&#39;s Viking 1 orbiter in 1976. This image is often cited as a classic example of pareidolia \u2013 the human tendency to perceive meaningful patterns, such as faces, in random or ambiguous visual data. Image credit: NASA/JPL, Viking 1 Orbiter (1976), public domain via Wikimedia Commons (link: https://commons.wikimedia.org/wiki/File.jpg).",src:n(8715).A+"",width:"640",height:"472"})}),"\n",(0,s.jsxs)("figcaption",{children:["Figure 9: The 'Face on Mars' captured by NASA's Viking 1 orbiter in 1976. This image is often cited as a classic example of pareidolia \u2013 the human tendency to perceive meaningful patterns, such as faces, in random or ambiguous visual data. Image credit: NASA/JPL, Viking 1 Orbiter (1976), public domain via Wikimedia Commons (link: ",(0,s.jsx)(i.a,{href:"https://commons.wikimedia.org/wiki/File:Martian_face_viking.jpg",children:"https://commons.wikimedia.org/wiki/File:Martian_face_viking.jpg"}),")."]}),"\n",(0,s.jsx)("span",{id:"perceptual-filling-in"}),"\n",(0,s.jsxs)(i.h3,{id:"perceptual-filling-in-3-min",children:["Perceptual 'filling in' ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"3 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"3 min"})})]}),"\n",(0,s.jsxs)(i.p,{children:["Our brains often 'fill in' missing or messy sensory data, drawing on past knowledge and context to create an experience that is fuller than that of the sensory information provided. An example of this is pareidolia, the tendency to see meaningful patterns in random or ambiguous things. This is why we might see a face on the surface of the moon or a human figure in the shadows on a dark street",(0,s.jsx)(o.A,{refNum:"71",refText:"Reference 71"}),". This ability to interpret incomplete sensory information is essential for navigating the messy reality of everyday perception. And it also offers creative opportunities. In particular, it points to the conclusion that not every detail needs perfect simulation. Strategic hints can prompt audiences to imagine the rest, easing technical demands without sacrificing immersion."]}),"\n",(0,s.jsx)("span",{id:"multisensory-attention"}),"\n",(0,s.jsxs)(i.h3,{id:"multisensory-attention-2-min",children:["Multisensory attention ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"2 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"2 min"})})]}),"\n",(0,s.jsx)(i.p,{children:"Multisensory cues are excellent at attracting and holding attention. Hearing a loud bang alongside a bright flash is more attention-grabbing than either of these alone. And in a performance or interactive exhibit, coordinating sound, light and even gentle tactile cues can effectively steer the audience's focus."}),"\n",(0,s.jsxs)(i.p,{children:["Attention can also be drawn by sensations which violate our expectations",(0,s.jsx)(o.A,{refNum:"72",refText:"Reference 72"}),". This suggests that deliberate deviations from multisensory 'realism' could be used to capture people's attention in interesting ways, e.g., in design",(0,s.jsx)(o.A,{refNum:"41",refText:"Reference 41"}),", where objects may appear to be made of one material but feel unexpectedly different to the touch (e.g. a surface that looks like hard stone but is actually soft), thereby creating surprise and increasing user interest or engagement."]}),"\n",(0,s.jsxs)(i.p,{children:["Once attention is focused on a particular event, it has a number of other important effects. For example, attention can enhance multisensory integration, amplifying effects such as the ventriloquist effect discussed earlier",(0,s.jsx)(o.A,{refNum:"67",refText:"Reference 67"}),". Attention can also selectively amplify some stimuli while suppressing others. The 'cocktail party effect' is a classic example whereby you can often tune out background noise to focus on a single conversation",(0,s.jsx)(o.A,{refNum:"73",refText:"Reference 73"}),". Interestingly, attending to lip movements in a noisy room has been found to make a speaker's voice perceptually louder, roughly the same as a +5 dB increase in sound level or about 150% of the original loudness",(0,s.jsx)(o.A,{refNum:"73",refText:"Reference 73"}),". And this amplification effect occurs in the other senses as well",(0,s.jsx)(o.A,{refNum:"74",refText:"Reference 74"}),", for example heightening visual contrast",(0,s.jsx)(o.A,{refNum:"75",refText:"Reference 75"}),", or making flavours seem richer or more pronounced",(0,s.jsx)(o.A,{refNum:"76",refText:"Reference 76"}),"."]}),"\n",(0,s.jsxs)(i.p,{children:["Attention directed toward emotional stimuli can also heighten affective responses, making emotionally charged experiences more intense",(0,s.jsx)(o.A,{refNum:"77",refText:"Reference 77"}),". Whether it's focusing on a beautifully plated meal or a dramatic moment in a film, attention can amplify the depth of an emotional experience by prioritising and enhancing relevant sensory cues."]}),"\n",(0,s.jsx)("span",{id:"holistic-experiential-integration"}),"\n",(0,s.jsxs)(i.h3,{id:"holistic-experiential-integration-1-min",children:["Holistic experiential integration ",(0,s.jsx)("span",{className:"reading-time",role:"note","aria-label":"1 minute read",children:(0,s.jsx)("span",{"aria-hidden":"true",children:"1 min"})})]}),"\n",(0,s.jsxs)(i.p,{children:["Audiences absorb far more than just the main show. From their first step into a venue, the lighting, ambient sounds, and even the scent of the lobby all shape their overall impression. Subtle touches, like a textured ticket or a gentle aroma, can make a lasting emotional impact. This highlights the importance of carefully designing the onboarding and offboarding phases of an experience (the 'whole arc'",(0,s.jsx)(o.A,{refNum:"31",refText:"Reference 31"}),") to ensure it feels inclusive, enjoyable and comfortable for everyone",(0,s.jsx)(o.A,{refNum:"78",refText:"Reference 78"})," ."]})]})}function u(e={}){const{wrapper:i}={...(0,a.R)(),...e.components};return i?(0,s.jsx)(i,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},8715(e,i,n){n.d(i,{A:()=>t});const t=n.p+"assets/images/image8-ea1feb56627416465b3d9aacaaad14c9.gif"}}]);